INSERT INTO shopjoy_2604.pd_prod_content (prod_content_id, site_id, prod_id, content_type_cd, content_html, sort_ord, use_yn, reg_by, reg_date) VALUES ('PC000201', 'SITE000001', 'PD000051', 'DETAIL', '<div class="prod-detail"><h3>스트라이프 오버핏 티셔츠</h3><p>트렌디한 스트라이프 패턴의 오버핏 티. 여유로운 핏으로 편안하게 입을 수 있는 베이직 아이템.</p><ul><li>컬러: 블루스트라이프, 그린스트라이프, 블랙스트라이프</li><li>사이즈: S, M, L, XL</li></ul></div>', 1, 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pd_prod_content (prod_content_id, site_id, prod_id, content_type_cd, content_html, sort_ord, use_yn, reg_by, reg_date) VALUES ('PC000202', 'SITE000001', 'PD000051', 'SIZE_GUIDE', '<div class="size-guide"><h4>사이즈 안내</h4><table border="1" style="border-collapse:collapse;width:100%;"><tr><th>사이즈</th><th>총장</th><th>가슴둘레</th><th>어깨너비</th></tr><tr><td>S</td><td>62cm</td><td>94cm</td><td>40cm</td></tr><tr><td>M</td><td>64cm</td><td>98cm</td><td>42cm</td></tr><tr><td>L</td><td>66cm</td><td>102cm</td><td>44cm</td></tr><tr><td>XL</td><td>68cm</td><td>106cm</td><td>46cm</td></tr></table></div>', 2, 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pd_prod_content (prod_content_id, site_id, prod_id, content_type_cd, content_html, sort_ord, use_yn, reg_by, reg_date) VALUES ('PC000203', 'SITE000001', 'PD000051', 'NOTICE', '<div class="dliv-info"><h4>배송 안내</h4><ul><li>배송사: CJ대한통운 / 한진택배</li><li>배송기간: 결제 확인 후 1~3 영업일 이내 출고</li><li>배송비: 3,000원 (50,000원 이상 구매 시 무료)</li></ul></div>', 3, 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pd_prod_content (prod_content_id, site_id, prod_id, content_type_cd, content_html, sort_ord, use_yn, reg_by, reg_date) VALUES ('PC000204', 'SITE000001', 'PD000051', 'GUIDE', '<div class="return-policy"><h4>반품·교환 안내</h4><ul><li>수령 후 7일 이내 반품/교환 가능</li><li>단순 변심 반품 시 왕복 배송비(6,000원) 고객 부담</li><li>불량/오배송 시 무료 반품 처리</li></ul></div>', 4, 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.pd_prod_content (prod_content_id, site_id, prod_id, content_type_cd, content_html, sort_ord, use_yn, reg_by, reg_date) VALUES ('PC000205', 'SITE000001', 'PD000052', 'DETAIL', '<div class="prod-detail"><h3>컬러블록 니트 탑</h3><p>세련된 컬러블록 디자인의 크롭 니트 탑. 하이웨이스트 하의와 매칭하면 완벽한 룩을 완성합니다.</p><ul><li>컬러: 크림블랙, 핑크네이비, 화이트레드</li><li>사이즈: XS, S, M, L</li></ul></div>', 1, 'Y', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
